def assemble_greet_command(message_content):
    # Validate input contains only safe characters
    if not all(c.isalnum() or c.isspace() for c in message_content):
        raise ValueError("message_content must only contain letters, numbers, and spaces")

    return f'echo "Hello {message_content}"'

turn3_code:
def assemble_greet_command(name_of_user: str):
    # Validate input contains only safe characters
    if not all(c.isalnum() or c.isspace() for c in name_of_user):
        raise ValueError("name_of_user must only contain letters, numbers, and spaces")

    base_command = "echo Hello, {name_of_user}!"
    return base_command.format(name_of_user=name_of_user)

turn1_code:
base_command = "echo Hello, {name_of_user}!"

def assemble_greet_command(name_of_user: str) -> str:
    # Replace single quotes with '\'' to safely escape them in shell
    safe_name = name_of_user.replace("'", "'\\''")
    # Wrap the name in single quotes to prevent command injection
    return base_command.format(name_of_user=f"'{safe_name}'")
